def size_to_bytes(size: str) -> int:

    size = size.strip().upper()
    multipliers = {
        'K': 1000,
        'M': 1000**2,
        'G': 1000**3,
        'T': 1000**4,
        'P': 1000**5,
        'E': 1000**6,
    }

    if size[-1] in multipliers:
        number = float(size[:-1])
        return int(number * multipliers[size[-1]])
    else:
        return int(size)

